//VARIABLES GLOBALES
TLibro *Biblioteca=NULL; //Vector dinámico de libros
int NumLibros=0; //Número de libros almacenados en el vector dinámico
int Tama=0; //Tamaño del vector dinámico. EL incremento será por bloque de 4 libros.
int IdAdmin=-1; //Identificador de Administración enviado al usuario.
Cadena NomFichero=""; //Nombre del último fichero binario que se ha cargado en memoria
int CampoOrdenacion=0; //Campo de ordenación por que se ordenarán los libros.
/* Devuelve 1 si el Ida es válido (coincide con el almacenado y es > 0) */
static int IdaValido(int Ida)
{
    return (IdAdmin > 0 && Ida == IdAdmin);
}
/*---------------------------------------------------------------------------
 * BuscarPorIsbn  –  Retorna la posición (0-based) del libro o -1
 *--------------------------------------------------------------------------*/
static int BuscarPorIsbn(const char *isbn)
{
    int i;
    for (i = 0; i < NumLibros; i++)
        if (strcmp(Biblioteca[i].Isbn, isbn) == 0)
            return i;
    return -1;
}
