/*Función que devuelve TRUE si el libro de la posición P1 está antes que el libro de la posición P2 comparándolo  
 mediante el Campo especificado */
bool_t EsMenor(int P1, int P2, int Campo)
{
	bool_t salida=FALSE;
	TLibro L1=Biblioteca[P1];
	TLibro L2=Biblioteca[P2];
	
	switch(Campo)
	{
		case 0: salida=strcoll(L1.Isbn,L2.Isbn)<0?TRUE:FALSE;
				break; 
		case 1: salida=strcoll(L1.Titulo,L2.Titulo)<0?TRUE:FALSE;
				break; 
		case 2: salida=strcoll(L1.Autor,L2.Autor)<0?TRUE:FALSE;
				break; 
		case 3: salida=L1.Anio<L2.Anio?TRUE:FALSE;
				break; 
		case 4: salida=strcoll(L1.Pais,L2.Pais)<0?TRUE:FALSE;
				break; 
		case 5: salida=strcoll(L1.Idioma,L2.Idioma)<0?TRUE:FALSE;
				break; 
		case 6: salida=L1.NoLibros<L2.NoLibros?TRUE:FALSE;
				break; 
		case 7: salida=L1.NoPrestados<L2.NoPrestados?TRUE:FALSE;
				break; 
		case 8: salida=L1.NoListaEspera<L2.NoListaEspera?TRUE:FALSE;
				break; 
	}
	return salida;
}
void OrdenarVector() {
    if (NumLibros <= 1)
		return;
	setlocale(LC_COLLATE, ""); 
    
    // Método de la burbuja usando EsMenor del profesor
    for (int i = 0; i < NumLibros - 1; i++) {
        for (int j = 0; j < NumLibros - i - 1; j++) {
            // Si el de la izquierda NO es menor que el de la derecha, los intercambiamos
            if (!EsMenor(j, j + 1, CampoOrdenacion)) {
                TLibro temp = Biblioteca[j];
                Biblioteca[j] = Biblioteca[j + 1];
                Biblioteca[j + 1] = temp;
            }
        }
    }
}

int * cargardatos_1_svc(TFichero *argp, struct svc_req *rqstp)
{
	static int  result;
	if(IdAdmin==-1 || argp->Ida != IdAdmin || argp->Ida<=0)
	{
		result=-1;
		return &result;
	}
	FILE *f=fopen(argp->NomFile,"rb");
	if(f==NULL)
	{
		result=0;
		return &result;
	}
	if(Biblioteca!=NULL)
	{
		free(Biblioteca);
		Biblioteca=NULL;
	}
	NumLibros=0;
	Tama=0;
	int numLibrosFichero;
	if(fread(&numLibrosFichero,sizeof(int),1,f)!=1)
	{
		fclose(f);
		result=0;
		return &result;
	}
	Tama=numLibrosFichero;
	if(Tama%4!=0)
	{
		Tama=Tama+(4-(Tama%4));
	}
	else if(Tama==0)
	{
		Tama=4;
	}

	//Uso malloc para crear el vector
	Biblioteca=(TLibro*)malloc(sizeof(TLibro)*Tama);
	if(Biblioteca==NULL)
	{
		fclose(f);
		result=0;
		return &result;
	}
	//Leo libros
	for(int i=0;i<numLibrosFichero;i++)
	{
		fread(&Biblioteca[i],sizeof(TLibro),1,f);
	}
	NumLibros=numLibrosFichero;
	fclose(f);
	strcpy(NomFichero,argp->NomFile);
	OrdenarVector();
	result=1;
	return &result;
}

bool_t *guardardatos_1_svc(int *argp, struct svc_req *rqstp)
{
	static bool_t  result;
	if(!IdaValido(*argp))
	{
		result=FALSE;
		return &result;
	}
	if(strlen(NomFichero)==0)
	{
		result=FALSE;
		return &result;
	}
	FILE *f=fopen(NomFichero,"wb");
	if(f==NULL)
	{
		result=FALSE;
		return &result;
	}
	fwrite(&NumLibros,sizeof(int),1,f);
	//Escribo libros
	for(int i=0;i<NumLibros;i++)
	{
		fwrite(&Biblioteca[i],sizeof(TLibro),1,f);
	}
	fclose(f);
	result=TRUE;

	return &result;
}

