int *retirar_1_svc(TComRet *argp, struct svc_req *rqstp)
{
	static int  result;
	int pos;
	if(!IdaValido(argp->Ida))
	{
		result=-1;
		return &result;
	}
	pos=BuscarPorIsbn(argp->Isbn);
	if(pos<0)
	{
		result=0;
		return &result;
	}
	if(Biblioteca[pos].NoLibros<argp->NoLibros)
	{
		result=2;
		return &result;
	}
	Biblioteca[pos].NoLibros-=argp->NoLibros;
	OrdenarVector();
	result=1;
	return &result;
}

